// Simple RSS data inspector
const items = $input.all();

console.log(`=== RSS Feed Analysis ===`);
console.log(`Total items received: ${items.length}`);

const analysis = [];

for (let i = 0; i < Math.min(items.length, 3); i++) {
  const item = items[i];
  console.log(`\n--- Item ${i+1} ---`);
  console.log(`Title: ${item.json.title}`);
  console.log(`Description: ${item.json.description || item.json.contentSnippet || 'No description'}`);
  console.log(`Link: ${item.json.link}`);
  console.log(`PubDate: ${item.json.pubDate || item.json.isoDate}`);
  console.log(`Available keys: ${Object.keys(item.json).join(', ')}`);

  analysis.push({
    json: {
      item_number: i + 1,
      title: item.json.title,
      description: item.json.description || item.json.contentSnippet || 'No description',
      link: item.json.link,
      pubDate: item.json.pubDate || item.json.isoDate,
      available_keys: Object.keys(item.json),
      raw_data_sample: JSON.stringify(item.json).substring(0, 500) + '...'
    }
  });
}

console.log(`\n=== Analysis Complete ===`);
return analysis;
